// Extraer textos de los mensajes del chat
const notes = $input.first().json._embedded?.notes || [];

const chatHistory = notes
  .filter(note => note.note_type === 'message' || note.note_type === 'common')
  .map(note => {
    const text = note.params?.text || note.text || '';
    const author = note.created_by === 0 ? 'Cliente' : 'Agente';
    return `${author}: ${text}`;
  })
  .join('\n---\n');

return [{ json: { chatHistory } }];

// Parsear la respuesta JSON de OpenAI
const response = $input.first().json;
let content = response.message?.content || response.choices?.[0]?.message?.content || JSON.stringify(response);

let datos;
try {
  datos = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  // Intentar extraer JSON del texto
  const match = content.match(/\{[\s\S]*\}/);
  datos = match ? JSON.parse(match[0]) : {
    nombre_cliente: 'No especificado',
    email_cliente: 'No especificado',
    servicio_solicitado: 'No especificado',
    detalles: 'No especificado',
    presupuesto: 'No especificado'
  };
}

// Agregar fecha y número de cotización
const now = new Date();
datos.fecha = now.toLocaleDateString('es-MX', { day: '2-digit', month: '2-digit', year: 'numeric' });
datos.numero_cotizacion = 'COT-' + now.getFullYear().toString().slice(-2) + 
  String(now.getMonth()+1).padStart(2,'0') + 
  String(now.getDate()).padStart(2,'0') + 
  String(now.getHours()).padStart(2,'0') + 
  String(now.getMinutes()).padStart(2,'0');

return [{ json: datos }];
